class MyResponsesPage{constructor(){this.responses=[],this.init()}async init(){document.getElementById("logout-btn").addEventListener("click",()=>{window.app.logout()}),await this.loadMyResponses()}async loadMyResponses(){const e=document.getElementById("loading"),s=document.getElementById("error-message"),n=document.getElementById("responses-container"),t=document.getElementById("responses-list");try{e.classList.remove("hidden"),s.classList.add("hidden"),n.classList.add("hidden");const i=await window.app.apiRequest("/surveys/my/data");if(this.responses=i,e.classList.add("hidden"),n.classList.remove("hidden"),!i||0===i.length)return void(t.innerHTML='<div class="empty-state"><h2>Ответов пока нет</h2><p>Вы еще не прошли ни одного опроса.</p></div>');this.renderResponses()}catch(n){e.classList.add("hidden"),s.classList.remove("hidden"),s.textContent="Ошибка загрузки ответов."}}renderResponses(){const e=document.getElementById("responses-list");e.innerHTML="",e.className="surveys-grid",this.responses.forEach(s=>{const n=document.createElement("div");n.className="response-card",n.innerHTML=`\n                <div class="response-header">\n                    <h3>${s.survey_title}</h3>\n                    <div class="response-date">\n                        ${new Date(s.submitted_at).toLocaleDateString("ru-RU")}\n                    </div>\n                </div>\n                <div class="response-content">\n                    <p>${s.survey_description||"Без описания"}</p>\n                    <div class="response-actions">\n                        <a href="/surveys/responses/${s.id}" class="btn btn-primary btn-sm">\n                            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">\n                                <path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"></path>\n                                <polyline points="14 2 14 8 20 8"></polyline>\n                                <line x1="16" y1="13" x2="8" y2="13"></line>\n                            </svg>\n                            Мои ответы\n                        </a>\n                        <a href="/surveys/${s.survey_id}/results" class="btn btn-secondary btn-sm">\n                            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">\n                                <path d="M3 3v18h18"></path>\n                                <rect x="7" y="10" width="4" height="9"></rect>\n                                <rect x="15" y="6" width="4" height="13"></rect>\n                            </svg>\n                            Результаты\n                        </a>\n                    </div>\n                </div>\n            `,e.appendChild(n)})}}document.addEventListener("DOMContentLoaded",()=>{new MyResponsesPage});